navigate_to.code:
target_x = int(args.get('x', 0))
target_y = int(args.get('y', 0))
max_steps = int(args.get('max_steps', 40))
for _ in range(max_steps):
    state = tools['get_game_state']()
    if 'battle' in state.get('context', '') or 'dialogue' in state.get('context', ''):
        tools['press_buttons'](buttons=['A']*4, reasoning='battle/dialogue')
        continue
    pos = state.get('player_position')
    if not pos: continue
    px, py = int(pos.get('x')), int(pos.get('y'))
    if px == target_x and py == target_y:
        break
    grid = tools['get_map_data']().get('grid')
    if not grid: break
    q = [(px, py, [])]
    seen = {(px, py)}
    path = []
    while q:
        cx, cy, p = q.pop(0)
        if cx == target_x and cy == target_y:
            path = p
            break
        for dx, dy, btn in [(0,-1,'UP'), (0,1,'DOWN'), (-1,0,'LEFT'), (1,0,'RIGHT')]:
            nx, ny = cx+dx, cy+dy
            if 0 <= ny < len(grid) and 0 <= nx < len(grid[0]):
                if grid[ny][nx] in {'.', 'D', 'I', '~', '!', 'O', '?'} or (nx == target_x and ny == target_y):
                    if (nx, ny) not in seen:
                        seen.add((nx, ny))
                        q.append((nx, ny, p+[btn]))
    if path:
        tools['press_buttons'](buttons=[path[0]], reasoning=f'step to {target_x},{target_y}')
    else:
        break
result = {'done': True, 'pos': (px, py)}

