    stuck_count = 0
    last_pos = None

    for _ in range(max_steps):
        state = tools['get_game_state']()
        pos = state.get('player_position', {})
        px, py = pos.get('x', 0), pos.get('y', 0)
        start = (px, py)

        if start == target:
            break

        if last_pos == start:
            stuck_count += 1
            if stuck_count >= 3:
                break
        else:
            stuck_count = 0
        last_pos = start

        data = tools['get_map_data']()
        grid = data['grid']

        queue = [(start, [])]
        visited = {start}
        walkable = {'.', 'D', 'I', '~'}

        path = None
        while queue:
            (x, y), p = queue.pop(0)
            if (x, y) == target:
                path = p
                break
            for dx, dy, btn in [(0,-1,'UP'), (0,1,'DOWN'), (-1,0,'LEFT'), (1,0,'RIGHT')]:
                nx, ny = x+dx, y+dy
                if 0 <= ny < len(grid) and 0 <= nx < len(grid[0]):
                    if grid[ny][nx] == 'D' and (nx, ny) != target:
                        continue
                    if grid[ny][nx] in walkable and (nx, ny) not in visited:
                        visited.add((nx, ny))
                        queue.append(((nx, ny), p + [btn]))

        if path:
