walk_to.code:
def solve():
    target_x, target_y = args.get('x'), args.get('y')
    max_moves = args.get('max_moves', 30)
    for i in range(max_moves):
        state = tools['get_game_state']()
        text = state.get('state_text', '')
        pos = state.get('player_position')
        if not pos:
            tools['press_buttons'](buttons=['WAIT'], reasoning='No pos')
            continue
        px, py = pos.get('x'), pos.get('y')

        is_battle = False
        if 'battle' in text.lower() or 'wild' in text.lower() or 'enemy' in text.lower() or 'fainted' in text.lower() or 'exp' in text.lower():
            is_battle = True

        if px == target_x and py == target_y and not is_battle:
            return {'status': 'arrived', 'pos': (px, py), 'moves': i}

        if is_battle:
            tools['press_buttons'](buttons=['A', 'A', 'A', 'A'], reasoning='Battle detected. Mashing A.')
            continue

        lines = text.split('\n')
        grid = []
        in_map = False
        for line in lines:
            if line.startswith('ASCII Map:'):
                in_map = True
                continue
            if in_map:
                if line.startswith('(') or line.strip() == '':
                    in_map = False
                    continue
                grid.append(line)
        if not grid:
            tools['press_buttons'](buttons=['WAIT'], reasoning='No grid')
            continue

        queue = [(px, py, [])]
        visited = set([(px, py)])
        path = None
        while queue:
            cx, cy, current_path = queue.pop(0)
            if cx == target_x and cy == target_y:
                path = current_path
                break
            for dx, dy, dname in [(0, -1, 'UP'), (0, 1, 'DOWN'), (-1, 0, 'LEFT'), (1, 0, 'RIGHT')]:
                nx, ny = cx + dx, cy + dy
                if 0 <= ny < len(grid) and 0 <= nx < len(grid[0]):
                    tile = grid[ny][nx]
                    if tile in ['.', 'D', 'I', '~', 'O', '↓', '←', '→', 'N'] or (nx == target_x and ny == target_y):
                        if tile == 'N' and not (nx == target_x and ny == target_y):
                            continue
                        if (nx, ny) not in visited:
                            visited.add((nx, ny))
                            queue.append((nx, ny, current_path + [dname]))

        if path:
            next_move = path[0]
            tools['press_buttons'](buttons=[next_move], reasoning=f'Moving {next_move} towards {target_x},{target_y}')
        else:
            return {'status': 'no_path', 'pos': (px, py)}

    return {'status': 'max_moves_reached'}

result = solve()

