bfs_move.code:
def solve():
    try:
        tx, ty = int(float(args.get('x', 5))), int(float(args.get('y', 5)))
        data = tools['get_map_data']()
        px, py = data['player']['x'], data['player']['y']
        if px == tx and py == ty: return 'arrived'
        grid = data['grid']
        q = [(px, py, [])]
        seen = {(px, py)}
        while q:
            cx, cy, p = q.pop(0)
            if cx == tx and cy == ty:
                chunk = p[:4]
                tools['press_buttons'](buttons=chunk, reasoning=f'moving to {tx},{ty}')
                return 'moved'
            for dx, dy, btn in [(0,-1,'UP'), (0,1,'DOWN'), (-1,0,'LEFT'), (1,0,'RIGHT')]:
                nx, ny = cx+dx, cy+dy
                if 0 <= ny < len(grid) and 0 <= nx < len(grid[0]):
                    if grid[ny][nx] in {'.', 'I', 'D', '~', '!', 'O'} or (nx == tx and ny == ty):
                        if (nx, ny) not in seen:
                            seen.add((nx, ny))
                            q.append((nx, ny, p+[btn]))
        return 'no path'
    except Exception as e:
        return str(e)
result = solve()

