target_x = args.get('x')
target_y = args.get('y')
max_moves = args.get('max_moves', 50)

if target_x is None or target_y is None:
    result = {'success': False, 'reason': 'Missing target x or y'}
else:
    import heapq
    data = tools['get_map_data']()
    grid = data['grid']
    start = (data['player']['x'], data['player']['y'])

    queue = [(0, start[0], start[1], [])]
    visited = {start: 0}
    walkable = {'.', 'D', 'I', '~'}

    path_found = None
    while queue:
        cost, x, y, path = heapq.heappop(queue)
        if x == target_x and y == target_y:
            path_found = path
            break

        for dx, dy, dname in [(0, -1, 'UP'), (0, 1, 'DOWN'), (-1, 0, 'LEFT'), (1, 0, 'RIGHT')]:
            nx, ny = x + dx, y + dy
            if 0 <= ny < len(grid) and 0 <= nx < len(grid[0]):
                char = grid[ny][nx]
                ncost = cost + 1
                if char == '~': ncost += 10

                nnx, nny = None, None
                is_jump = False
                if char in walkable:
                    nnx, nny = nx, ny
                elif char == '↓' and dname == 'DOWN':
                    nnx, nny = nx, ny + 1
                    is_jump = True
                elif char == '→' and dname == 'RIGHT':
                    nnx, nny = nx + 1, ny
                    is_jump = True
                elif char == '←' and dname == 'LEFT':
                    nnx, nny = nx - 1, ny
                    is_jump = True

                if nnx is not None and 0 <= nny < len(grid) and 0 <= nnx < len(grid[0]):
                    if is_jump and grid[nny][nnx] not in walkable:
                        continue
                    if (nnx, nny) not in visited or ncost < visited[(nnx, nny)]:
                        visited[(nnx, nny)] = ncost
                        heapq.heappush(queue, (ncost, nnx, nny, path + [dname]))

    if not path_found:
        result = {'success': False, 'reason': 'No path found'}
    else:
        moves_made = 0
        final_pos = start
        interrupted = False
        last_pos = start
        stuck_count = 0

        for move in path_found[:max_moves]:
            tools['press_buttons'](buttons=[move], reasoning=f'Following BFS path to {target_x},{target_y}')
            moves_made += 1
            st = tools['get_game_state']()
            pos = st.get('player_position', {})
            px, py = pos.get('x', 0), pos.get('y', 0)
            final_pos = (px, py)

            if final_pos == last_pos:
                stuck_count += 1
                if stuck_count >= 2:
                    break
            else:
                stuck_count = 0
            last_pos = final_pos

            text = st.get('state_text', '')
            if 'Game State: overworld' not in text:
                interrupted = True
                break

        result = {'success': (final_pos[0] == target_x and final_pos[1] == target_y), 'moves': moves_made, 'final_pos': final_pos, 'path_length': len(path_found), 'interrupted': interrupted}

