warp_coords = {(w['x'], w['y']) for w in warps if (w['x'], w['y']) != (target_x, target_y)}

def get_path(start, goal):
    queue = collections.deque([(start, [])])
    seen = {start}
    while queue:
        (x, y), path = queue.popleft()
        if (x, y) == goal: return path
        for dx, dy, btn in [(0, -1, 'UP'), (0, 1, 'DOWN'), (-1, 0, 'LEFT'), (1, 0, 'RIGHT')]:
            nx, ny = x + dx, y + dy
            if 0 <= ny < len(grid) and 0 <= nx < len(grid[0]):
                tile = grid[ny][nx]
                if tile in ['.', 'I', '?', 'O', 'D'] and (nx, ny) not in warp_coords:
                    if (nx, ny) not in seen:
                        seen.add((nx, ny))
                        queue.append(((nx, ny), path + [btn]))
    return None

path = get_path((pos['x'], pos['y']), (target_x, target_y))

if path:
    moves_made = 0
    stuck_count = 0
    last_pos = (pos['x'], pos['y'])

